package test.rice.obj;

import main.rice.obj.*;
import org.junit.jupiter.api.*;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;

/**
 * Agent tests covering equals, hashCode, toString edge cases, and cross-type comparisons.
 */
class AgentPyObjTest {

    // ==================== Primitive equals/hashCode ====================

    @Test
    void testPyIntObjEquals() {
        PyIntObj a = new PyIntObj(42);
        PyIntObj b = new PyIntObj(42);
        PyIntObj c = new PyIntObj(99);
        assertEquals(a, b);
        assertNotEquals(a, c);
        assertEquals(a.hashCode(), b.hashCode());
    }

    @Test
    void testPyIntObjNotEqualToNull() {
        PyIntObj a = new PyIntObj(42);
        assertNotEquals(a, null);
    }

    @Test
    void testPyIntObjNotEqualToString() {
        PyIntObj a = new PyIntObj(1);
        assertNotEquals(a, "1");
    }

    @Test
    void testPyBoolObjEquals() {
        PyBoolObj t1 = new PyBoolObj(true);
        PyBoolObj t2 = new PyBoolObj(true);
        PyBoolObj f1 = new PyBoolObj(false);
        assertEquals(t1, t2);
        assertNotEquals(t1, f1);
        assertEquals(t1.hashCode(), t2.hashCode());
    }

    @Test
    void testPyBoolObjToString() {
        assertEquals("True", new PyBoolObj(true).toString());
        assertEquals("False", new PyBoolObj(false).toString());
    }

    @Test
    void testPyFloatObjEquals() {
        PyFloatObj a = new PyFloatObj(3.14);
        PyFloatObj b = new PyFloatObj(3.14);
        PyFloatObj c = new PyFloatObj(2.71);
        assertEquals(a, b);
        assertNotEquals(a, c);
        assertEquals(a.hashCode(), b.hashCode());
    }

    @Test
    void testPyFloatObjToString() {
        assertEquals("3.14", new PyFloatObj(3.14).toString());
    }

    @Test
    void testPyCharObjEquals() {
        PyCharObj a = new PyCharObj('x');
        PyCharObj b = new PyCharObj('x');
        PyCharObj c = new PyCharObj('y');
        assertEquals(a, b);
        assertNotEquals(a, c);
        assertEquals(a.hashCode(), b.hashCode());
    }

    @Test
    void testPyIntObjGetValue() {
        assertEquals(42, new PyIntObj(42).getValue());
    }

    @Test
    void testPyBoolObjGetValue() {
        assertEquals(true, new PyBoolObj(true).getValue());
    }

    @Test
    void testPyFloatObjGetValue() {
        assertEquals(3.14, new PyFloatObj(3.14).getValue());
    }

    @Test
    void testPyCharObjGetValue() {
        assertEquals('x', new PyCharObj('x').getValue());
    }

    @Test
    void testPyIntObjToString() {
        assertEquals("42", new PyIntObj(42).toString());
        assertEquals("-1", new PyIntObj(-1).toString());
        assertEquals("0", new PyIntObj(0).toString());
    }

    // ==================== Cross-type inequality ====================

    @Test
    void testIntNotEqualToFloat() {
        PyIntObj i = new PyIntObj(1);
        PyFloatObj f = new PyFloatObj(1.0);
        assertNotEquals(i, f);
    }

    @Test
    void testIntNotEqualToBool() {
        PyIntObj i = new PyIntObj(1);
        PyBoolObj b = new PyBoolObj(true);
        assertNotEquals(i, b);
    }

    @Test
    void testListNotEqualToTuple() {
        PyListObj<PyIntObj> list = new PyListObj<>(Arrays.asList(new PyIntObj(1)));
        PyTupleObj<PyIntObj> tuple = new PyTupleObj<>(Arrays.asList(new PyIntObj(1)));
        assertNotEquals(list, tuple);
    }

    // ==================== List ====================

    @Test
    void testListEquals() {
        PyListObj<PyIntObj> a = new PyListObj<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2)));
        PyListObj<PyIntObj> b = new PyListObj<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2)));
        PyListObj<PyIntObj> c = new PyListObj<>(Arrays.asList(new PyIntObj(1), new PyIntObj(3)));
        assertEquals(a, b);
        assertNotEquals(a, c);
        assertEquals(a.hashCode(), b.hashCode());
    }

    @Test
    void testListToStringMulti() {
        PyListObj<PyIntObj> list = new PyListObj<>(
            Arrays.asList(new PyIntObj(1), new PyIntObj(2), new PyIntObj(3)));
        assertEquals("[1, 2, 3]", list.toString());
    }

    @Test
    void testNestedListToString() {
        PyListObj<PyListObj<PyIntObj>> nested = new PyListObj<>(Arrays.asList(
            new PyListObj<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2))),
            new PyListObj<>(Arrays.asList(new PyIntObj(3), new PyIntObj(4)))
        ));
        assertEquals("[[1, 2], [3, 4]]", nested.toString());
    }

    // ==================== Tuple ====================

    @Test
    void testTupleEquals() {
        PyTupleObj<PyIntObj> a = new PyTupleObj<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2)));
        PyTupleObj<PyIntObj> b = new PyTupleObj<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2)));
        assertEquals(a, b);
        assertEquals(a.hashCode(), b.hashCode());
    }

    @Test
    void testTupleToStringMulti() {
        PyTupleObj<PyIntObj> tuple = new PyTupleObj<>(
            Arrays.asList(new PyIntObj(1), new PyIntObj(2), new PyIntObj(3)));
        assertEquals("(1, 2, 3)", tuple.toString());
    }

    @Test
    void testNestedTupleToString() {
        PyTupleObj<PyTupleObj<PyIntObj>> nested = new PyTupleObj<>(Arrays.asList(
            new PyTupleObj<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2))),
            new PyTupleObj<>(Arrays.asList(new PyIntObj(3), new PyIntObj(4)))
        ));
        assertEquals("((1, 2), (3, 4))", nested.toString());
    }

    // ==================== Set ====================

    @Test
    void testSetEquals() {
        Set<PyIntObj> s1 = new HashSet<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2)));
        Set<PyIntObj> s2 = new HashSet<>(Arrays.asList(new PyIntObj(2), new PyIntObj(1)));
        PySetObj<PyIntObj> a = new PySetObj<>(s1);
        PySetObj<PyIntObj> b = new PySetObj<>(s2);
        assertEquals(a, b);
        assertEquals(a.hashCode(), b.hashCode());
    }

    @Test
    void testSetToStringMulti() {
        Set<PyIntObj> s = new LinkedHashSet<>();
        s.add(new PyIntObj(1));
        s.add(new PyIntObj(2));
        s.add(new PyIntObj(3));
        PySetObj<PyIntObj> set = new PySetObj<>(s);
        assertEquals("{1, 2, 3}", set.toString());
    }

    // ==================== Dict ====================

    @Test
    void testDictEquals() {
        Map<PyIntObj, PyIntObj> m1 = new LinkedHashMap<>();
        m1.put(new PyIntObj(1), new PyIntObj(2));
        Map<PyIntObj, PyIntObj> m2 = new LinkedHashMap<>();
        m2.put(new PyIntObj(1), new PyIntObj(2));
        assertEquals(new PyDictObj<>(m1), new PyDictObj<>(m2));
    }

    @Test
    void testDictToStringMulti() {
        Map<PyIntObj, PyStringObj> m = new LinkedHashMap<>();
        m.put(new PyIntObj(1), new PyStringObj("a"));
        m.put(new PyIntObj(2), new PyStringObj("b"));
        assertEquals("{1: 'a', 2: 'b'}", new PyDictObj<>(m).toString());
    }

    @Test
    void testNestedDictToString() {
        Map<PyIntObj, PyIntObj> inner = new LinkedHashMap<>();
        inner.put(new PyIntObj(2), new PyIntObj(3));
        Map<PyIntObj, PyDictObj<PyIntObj, PyIntObj>> outer = new LinkedHashMap<>();
        outer.put(new PyIntObj(1), new PyDictObj<>(inner));
        assertEquals("{1: {2: 3}}", new PyDictObj<>(outer).toString());
    }

    // ==================== String ====================

    @Test
    void testStringEquals() {
        PyStringObj a = new PyStringObj("hello");
        PyStringObj b = new PyStringObj("hello");
        PyStringObj c = new PyStringObj("world");
        assertEquals(a, b);
        assertNotEquals(a, c);
        assertEquals(a.hashCode(), b.hashCode());
    }

    @Test
    void testStringToString() {
        assertEquals("'hello'", new PyStringObj("hello").toString());
        assertEquals("'a'", new PyStringObj("a").toString());
    }

    @Test
    void testStringGetValueSize() {
        assertEquals(5, new PyStringObj("hello").getValue().size());
        assertEquals(0, new PyStringObj("").getValue().size());
    }

    // ==================== Deeply nested toString ====================

    @Test
    void testDeeplyNestedToString() {
        // [[{1: (2, 3)}]]
        PyTupleObj<PyIntObj> innerTuple = new PyTupleObj<>(
            Arrays.asList(new PyIntObj(2), new PyIntObj(3)));
        Map<PyIntObj, PyTupleObj<PyIntObj>> innerMap = new LinkedHashMap<>();
        innerMap.put(new PyIntObj(1), innerTuple);
        PyDictObj<PyIntObj, PyTupleObj<PyIntObj>> innerDict = new PyDictObj<>(innerMap);
        PyListObj<PyDictObj<PyIntObj, PyTupleObj<PyIntObj>>> middleList =
            new PyListObj<>(Arrays.asList(innerDict));
        PyListObj<PyListObj<PyDictObj<PyIntObj, PyTupleObj<PyIntObj>>>> deeplyNested =
            new PyListObj<>(Arrays.asList(middleList));
        assertEquals("[[{1: (2, 3)}]]", deeplyNested.toString());
    }

    // ==================== Self-equality ====================

    @Test
    void testSelfEquality() {
        PyIntObj i = new PyIntObj(1);
        assertEquals(i, i);
        PyListObj<PyIntObj> list = new PyListObj<>(Arrays.asList(new PyIntObj(1)));
        assertEquals(list, list);
    }
}

package main.rice.obj;

import java.util.List;
import java.util.StringJoiner;

/**
 * Represents a Python list object.
 *
 * @param <InnerType> the type of elements in the list
 */
public class PyListObj<InnerType extends APyObj<?>> extends AIterablePyObj<List<InnerType>> {

    public PyListObj(List<InnerType> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        StringJoiner sj = new StringJoiner(", ", "[", "]");
        for (InnerType elem : value) {
            sj.add(elem.toString());
        }
        return sj.toString();
    }
}

package main.rice.obj;

import java.util.Objects;

/**
 * Abstract base class for all Python objects.
 *
 * @param <ValueType> the Java type of the underlying value
 */
public abstract class APyObj<ValueType> {

    protected ValueType value;

    /**
     * Returns the underlying Java value.
     */
    public ValueType getValue() {
        return this.value;
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null || this.getClass() != obj.getClass()) return false;
        APyObj<?> other = (APyObj<?>) obj;
        return Objects.equals(this.value, other.value);
    }

    @Override
    public int hashCode() {
        return Objects.hashCode(this.value);
    }
}

