package main.rice.obj;

/**
 * Abstract base class for iterable Python objects (lists, tuples, sets, dicts, strings).
 *
 * @param <ContainerType> the Java collection type holding the elements
 */
public abstract class AIterablePyObj<ContainerType> extends APyObj<ContainerType> {
}

package main.rice.obj;

import java.util.ArrayList;
import java.util.List;

/**
 * Represents a Python string object.
 * Internally stored as a list of PyCharObj elements.
 */
public class PyStringObj extends AIterablePyObj<List<PyCharObj>> {

    public PyStringObj(String s) {
        this.value = new ArrayList<>();
        for (char c : s.toCharArray()) {
            this.value.add(new PyCharObj(c));
        }
    }

    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("'");
        for (PyCharObj c : value) {
            sb.append(c.getValue());
        }
        sb.append("'");
        return sb.toString();
    }
}

