package main.rice.obj;

import java.util.Set;
import java.util.StringJoiner;

/**
 * Represents a Python set object.
 *
 * @param <InnerType> the type of elements in the set
 */
public class PySetObj<InnerType extends APyObj<?>> extends AIterablePyObj<Set<InnerType>> {

    public PySetObj(Set<InnerType> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        if (value.isEmpty()) {
            return "set()";
        }
        StringJoiner sj = new StringJoiner(", ", "{", "}");
        for (InnerType elem : value) {
            sj.add(elem.toString());
        }
        return sj.toString();
    }
}

package main.rice.obj;

/**
 * Represents a Python boolean object (True/False).
 */
public class PyBoolObj extends APyObj<Boolean> {

    public PyBoolObj(Boolean value) {
        this.value = value;
    }

    @Override
    public String toString() {
        return value ? "True" : "False";
    }
}

package main.rice.obj;

import java.util.List;

/**
 * Represents a Python tuple object.
 *
 * @param <InnerType> the type of elements in the tuple
 */
public class PyTupleObj<InnerType extends APyObj<?>> extends AIterablePyObj<List<InnerType>> {

    public PyTupleObj(List<InnerType> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("(");
        for (int i = 0; i < value.size(); i++) {
            if (i > 0) sb.append(", ");
            sb.append(value.get(i).toString());
        }
        if (value.size() == 1) sb.append(",");
        sb.append(")");
        return sb.toString();
    }
}

package main.rice.obj;

/**
 * Represents a Python character (single-character string).
 */
public class PyCharObj extends APyObj<Character> {

    public PyCharObj(Character value) {
        this.value = value;
    }

    @Override
    public String toString() {
        return "'" + value + "'";
    }
}

package main.rice.obj;

import java.util.Map;
import java.util.StringJoiner;

/**
 * Represents a Python dictionary object.
 *
 * @param <KeyType> the type of keys
 * @param <ValType> the type of values
 */
public class PyDictObj<KeyType extends APyObj<?>, ValType extends APyObj<?>>
        extends AIterablePyObj<Map<KeyType, ValType>> {

    public PyDictObj(Map<KeyType, ValType> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        StringJoiner sj = new StringJoiner(", ", "{", "}");
        for (Map.Entry<KeyType, ValType> entry : value.entrySet()) {
            sj.add(entry.getKey().toString() + ": " + entry.getValue().toString());
        }
        return sj.toString();
    }
}

